import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { Plus, Search, Filter, Calendar, Tag, Trash2, X, Save } from 'lucide-react';
import '../styles/Despesas.css';

const Despesas = () => {
  const [despesas, setDespesas] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [itemEditando, setItemEditando] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    buscarDados();
  }, []);

  async function buscarDados() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('compras')
        .select(`*, categorias (nome, cor)`)
        .eq('tipo_despesa', 'Gastos Variáveis')
        .order('data_compra', { ascending: false });

      const { data: dataCat } = await supabase.from('categorias').select('*');
      if (error) throw error;
      setDespesas(data || []);
      setCategorias(dataCat || []);
    } catch (error) {
      console.error("Erro:", error);
    } finally {
      setLoading(false);
    }
  }

  const formatarMoeda = (valor) => {
    return Number(valor).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  const handleMascaraMoeda = (e) => {
    let valor = e.target.value.replace(/\D/g, "");
    const valorNumerico = (Number(valor) / 100).toFixed(2);
    const valorFormatado = new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(valorNumerico);
    setItemEditando({ ...itemEditando, valor_exibicao: valorFormatado });
  };

  const handleAbrirModal = (item) => {
    const valorInicial = formatarMoeda(item.valor_total);
    setItemEditando({ ...item, valor_exibicao: valorInicial });
    setIsModalOpen(true);
  };

  const handleSalvarEdicao = async (e) => {
    e.preventDefault();
    try {
      const valorLimpo = Number(itemEditando.valor_exibicao.replace(/[^\d,]/g, '').replace(',', '.'));
      const { error } = await supabase
        .from('compras')
        .update({
          descricao: itemEditando.descricao,
          valor_total: valorLimpo,
          data_compra: itemEditando.data_compra,
          categoria_id: itemEditando.categoria_id,
        })
        .eq('id', itemEditando.id);

      if (error) throw error;
      setIsModalOpen(false);
      buscarDados();
    } catch (error) {
      alert("Erro ao salvar.");
    }
  };

  const handleExcluir = async () => {
    if (window.confirm(`Excluir "${itemEditando.descricao}"?`)) {
      const { error } = await supabase.from('compras').delete().eq('id', itemEditando.id);
      if (!error) {
        setIsModalOpen(false);
        buscarDados();
      }
    }
  };

  const filteredDespesas = despesas.filter(d => 
    d.descricao.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="desp-premium-wrapper">
      {/* Header e Resumo (mantenha igual ao anterior) */}
      <div className="desp-top-layout">
        <header className="desp-panel desp-header-area">
          <div className="desp-title-area">
            <h1>Despesas</h1>
            <p>Pagamentos à vista e variáveis</p>
          </div>
          <div className="desp-search-box">
            <Search size={18} color="#94a3b8" />
            <input 
              type="text" 
              placeholder="Pesquisar..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </header>
        <div className="desp-panel desp-summary-card">
          <span className="summary-label">Total do Período</span>
          <h2 className="summary-value">{formatarMoeda(filteredDespesas.reduce((acc, curr) => acc + Number(curr.valor_total), 0))}</h2>
        </div>
      </div>

      {/* Lista Principal com Novo Estilo */}
      <main className="desp-panel">
        <div className="list-header">
          <h3 style={{fontWeight: 800, color: '#475569', margin: 0}}>Movimentações</h3>
          <Filter size={18} color="#94a3b8" />
        </div>

        <div className="desp-list">
          {loading ? (
            <div style={{padding: '40px', textAlign: 'center'}}>Carregando...</div>
          ) : filteredDespesas.map((item) => (
            <div key={item.id} className="desp-item-row" onClick={() => handleAbrirModal(item)}>
              
              <div className="desp-left-content">
                {/* Indicador de cor da categoria */}
                <div className="cat-indicator" style={{ backgroundColor: item.categorias?.cor || '#ccc' }}></div>
                
                <div className="desp-details">
                  {/* Linha 1: Item */}
                  <span className="desp-desc">{item.descricao}</span>
                  
                  {/* Linha 2: Data, Categoria e Pagamento */}
                  <div className="desp-meta">
                    <span className="meta-tag">
                      <Calendar size={12} /> 
                      {new Date(item.data_compra).toLocaleDateString('pt-BR')}
                    </span>
                    <span className="meta-tag">
                      <Tag size={12} /> 
                      {item.categorias?.nome}
                    </span>
                    <span className="method-badge">
                      {item.forma_pagamento || 'Dinheiro'}
                    </span>
                  </div>
                </div>
              </div>

              {/* Valor maior à direita */}
              <span className="desp-value">{formatarMoeda(item.valor_total)}</span>
              
            </div>
          ))}
        </div>
      </main>

      {/* Modal e FAB (mantenha os blocos de código anteriores) */}
      {/* ... */}
      <button className="desp-fab" onClick={() => navigate('/lancamento')}>
        <Plus size={30} />
      </button>

      {/* Inclusão do código do modal aqui para garantir que funcione */}
      {isModalOpen && itemEditando && (
        <div className="modal-overlay" onClick={() => setIsModalOpen(false)}>
           <div className="edit-modal" onClick={e => e.stopPropagation()}>
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
              <h2 style={{margin: 0, fontWeight: 900, letterSpacing: '-1px', color: '#0f172a'}}>Detalhes</h2>
              <button onClick={() => setIsModalOpen(false)} style={{background: '#f1f5f9', border: 'none', padding: '10px', borderRadius: '14px', cursor: 'pointer'}}>
                <X size={20} color="#64748b" />
              </button>
            </div>

            <form onSubmit={handleSalvarEdicao} className="edit-form-grid">
              <div className="form-group">
                <label>O que foi comprado?</label>
                <input type="text" value={itemEditando.descricao} onChange={e => setItemEditando({...itemEditando, descricao: e.target.value})} required />
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>Valor</label>
                  <input type="text" value={itemEditando.valor_exibicao} onChange={handleMascaraMoeda} required />
                </div>
                <div className="form-group">
                  <label>Data</label>
                  <input type="date" value={itemEditando.data_compra} onChange={e => setItemEditando({...itemEditando, data_compra: e.target.value})} required />
                </div>
              </div>

              <div className="form-group">
                <label>Categoria</label>
                <select value={itemEditando.categoria_id} onChange={e => setItemEditando({...itemEditando, categoria_id: e.target.value})}>
                  {categorias.map(cat => (
                    <option key={cat.id} value={cat.id}>{cat.nome}</option>
                  ))}
                </select>
              </div>

              <div className="modal-footer-actions">
                <button type="submit" className="btn-save-full"><Save size={18} /> Salvar Alterações</button>
                <button type="button" className="btn-delete-full" onClick={handleExcluir}><Trash2 size={18} /> Excluir Lançamento</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Despesas;
